const MobileIcon = ({ className }) => {
  return (
    <svg
      className={className}
      width="11"
      height="11"
      viewBox="0 0 11 11"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path
        d="M6.66535 4.33465H11V6.66535H6.66535V11H4.33465V6.66535H0V4.33465H4.33465V0H6.66535V4.33465Z"
        fill="#75E883"
      />
    </svg>
  );
};

export const Resolution = () => {
  const ref = useRef<HTMLDivElement>(null);
  const statsContainerRef = useRef<HTMLDivElement>(null);

  const isMobile = useMediaQuery('(max-width: 480px)');

  useEffect(() => {
    const typed = new Typed(ref.current, {
      strings: [
        `function empowerCompany(company) {
  company.support = new AI_Agent({

    scalable: true,
    intelligent: true,
    autonomous: true,
    features: {
      learn: true,
      adapt: true,
      connectInRealTime: true
    }
  });

  return company;
}

function empowerCompany(company) {
  company.support = new AI_Agent({

    scalable: true,
    intelligent: true,
    autonomous: true,
    features: {
      learn: true,
      adapt: true,
      connectInRealTime: true
    }
  });

  return company;
}`,
      ],
      typeSpeed: 0,
      loop: false,
    });

    typed.stop();

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          typed.start();
          observer.disconnect();
        }
      },
      { threshold: 0.3 },
    );

    if (statsContainerRef.current) {
      observer.observe(statsContainerRef.current);
    }

    return () => {
      typed.destroy();
      observer.disconnect();
    };
  }, []);

  return (
    <div className={styles.container} ref={statsContainerRef}>
      {isMobile ? (
        <>
          <MobileBG className={cx(styles.svgBg, styles.mobileBg)} />
          <MobileIcon className={styles.mobileIcon} />
        </>
      ) : (
        <BG className={styles.svgBg} />
      )}
      <div className={styles.bg}>
        <div ref={ref} className={styles.code}></div>
      </div>
      <div className={styles.text}>
        <TextAnimation animationType="fadeInUp" delay={0} duration={600}>
          {i18n('solvea.Home_downbanner_desc')}
        </TextAnimation>
      </div>
      <a href={getLink('/contact')} target={'_blank'} className={styles.btn}>
        <Button>{i18n('solvea.Home_downbanner_button')}</Button>
      </a>
    </div>
  );
};
